          <span>Телефон кассы: 8(999)999-99-99</span>
          <span>theatre@gmail.com</span>
          <span>Время работы: 10:00–19:00</span>
        </div>
        <span className="footer__address">адрес</span>
      </div>
    </footer>
  );
}
